# Scratch：跟「如果那麼」積木一樣喔
天氣 = input("今天天氣如何？（晴天/下雨）：")
if 天氣 == "晴天":
    print("去外面玩吧！")
else:
    print("在家寫程式吧！")

# Scratch：跟「如果那麼否則如果那麼」積木一樣喔
小時 = int(input("現在幾點？（0～23）："))
if 小時 < 10:
    print("早安！")
elif 小時 < 17:
    print("午安！")
else:
    print("晚安！")

# Scratch：跟「重複」積木一樣喔
for 次數 in range(5):
    print(str(次數 + 1) + " 次：你好！")
